const executed = [];
const mockExec = function(cmd, callback) {
    executed.push(cmd);
    if (callback) callback(null, '', '');
    return { stdout: '', stderr: '' };
};

const child_process = require('child_process');
child_process.exec = mockExec;

function vulnerable(address) {
    const req = { body: { address: address } };
    const res = { render: function(view, options) {} };
    child_process.exec('ping -c 2 ' + req.body.address, function (err, stdout, stderr) {});
}

const payloads = [
    "127.0.0.1",
    "; id",
    "| whoami",
    "`id`",
    "&& ls",
    "& echo vulnerable &",
    "|| id",
    "$(id)"
];

let triggered = false;
let triggerDetail = '';
let capturedArgument = '';
let usedPayload = '';

for (const p of payloads) {
    executed.length = 0;
    vulnerable(p);
    for (const cmd of executed) {
        if (cmd !== 'ping -c 2 127.0.0.1' && (cmd.includes(';') || cmd.includes('|') || cmd.includes('`') || cmd.includes('$') || cmd.includes('&') || cmd.includes('||'))) {
            triggered = true;
            triggerDetail = `Command injection detected: exec called with "${cmd}"`;
            capturedArgument = cmd;
            usedPayload = p;
            break;
        }
    }
    if (triggered) break;
}

const result = {
    triggered: triggered,
    target_function_called: true,
    sink_called: triggered,
    sink_name: "child_process.exec",
    captured_argument: capturedArgument,
    payload: usedPayload,
    trigger_detail: triggerDetail
};

console.log('AUDITAGENTX_RESULT_JSON=' + JSON.stringify(result));
if (triggered) {
    console.log('AUDITAGENTX_VULN_TRIGGERED');
} else {
    console.log('AUDITAGENTX_NO_TRIGGER');
}
